package main

import (
	"encoding/json"
	"fmt"
	"net/http"

	"github.com/go-sql-driver/mysql"
)

type Order struct {
	ID    int    `json:"id"`
	User  string `json:"user"`
	Items []Item `json:"items"`
}

type Item struct {
	Name     string `json:"name"`
	Quantity int    `json:"quantity"`
	Price    float64`json:"price"`
}

func getOrderDetailsHandler(db *sql.DB) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		user := r.Context().Value("user").(string)
		orderID := r.URL.Path[len("/order/"):]

		var order Order
		err := db.QueryRow("SELECT id, user FROM orders WHERE id = ? AND user = ?", orderID, user).Scan(&order.ID, &order.User)
		if err != nil {
			http.Error(w, "Order not found", http.StatusNotFound)
			return
		}

		rows, err := db.Query("SELECT name, quantity, price FROM items WHERE order_id = ?", order.ID)
		if err != nil {
			http.Error(w, "Internal Server Error", http.StatusInternalServerError)
			return
		}
		defer rows.Close()

		var items []Item
		for rows.Next() {
			var item Item
			err := rows.Scan(&item.Name, &item.Quantity, &item.Price)
			if err != nil {
				http.Error(w, "Internal Server Error", http.StatusInternalServerError)
				return
			}
			items = append(items, item)
		}

		order.Items = items
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(order)
	}
}

